// ââ Attach Task Events ââ
function mtb_attach_task_events(){
$('.mtb-field-select').off('change').on('change',function(){mtb_update_task_field($(this).data('task'),$(this).data('field'),$(this).val());});

$('.mtb-assigned-select').off('change').on('change',function(){
var userEmail=$(this).val();
var taskName=$(this).data('task');
var task=mtb_allTasks.find(function(t){return t.name===taskName;});
var currentAssigns=[];
if(task&&task._assign){try{currentAssigns=JSON.parse(task._assign);}catch(e){}}
if(userEmail){
// Use reassign API — removes all old assignees, adds new one
frappe.call({method:'reassign_task',args:{task_name:taskName,new_assignee:userEmail},callback:function(r){
if(r&&r.message&&r.message.success){
frappe.show_alert({message:r.message.message||'Reassigned',indicator:'green'});
mtb_refresh();
}else{
frappe.show_alert({message:(r&&r.message&&r.message.error)?r.message.error:'Reassignment failed',indicator:'red'});
mtb_refresh();
}
},error:function(){
// Fallback: direct assign_to.add if server script not available
frappe.xcall('frappe.desk.form.assign_to.add',{doctype:'Task',name:taskName,assign_to:[userEmail]}).then(function(){
frappe.show_alert({message:'Assigned',indicator:'green'});mtb_refresh();
});
}});
}else{
// Unassign: remove all current assignees
if(currentAssigns.length>0){
var removePromises=currentAssigns.map(function(u){return frappe.xcall('frappe.desk.form.assign_to.remove',{doctype:'Task',name:taskName,assign_to:u});});
Promise.all(removePromises).then(function(){
frappe.show_alert({message:'Unassigned',indicator:'orange'});mtb_refresh();
});
}
}
});

