/**
 * Team Pulse Dashboard - Frappe Web Page
 * Manager-facing analytics dashboard showing team workload, risk buckets, and weekly hours.
 * Designed for Frappe Website pages (not Desk), uses Bootstrap 3, jQuery, frappe.xcall().
 *
 * Expected HTML: <div id="team-pulse-dashboard"></div>
 */

(function () {
    "use strict";

    /* ------------------------------------------------------------------ */
    /*  COLOUR PALETTE                                                     */
    /* ------------------------------------------------------------------ */
    var COLORS = {
        status: {
            "Open":           "#3182CE",
            "Working":        "#D69E2E",
            "Pending Review": "#805AD5",
            "Completed":      "#38A169",
            "Cancelled":      "#A0AEC0",
            "Overdue":        "#E53E3E"
        },
        priority: {
            "Low":    "#38A169",
            "Medium": "#D69E2E",
            "High":   "#E53E3E",
            "Urgent": "#C53030"
        },
        bg:            "#F7FAFC",
        contentBg:     "#fff",
        border:        "#E2E8F0",
        textPrimary:   "#2D3748",
        textSecondary: "#718096"
    };

    var BUCKET_META = [
        { key: "overdue",   label: "Overdue",   icon: "\uD83D\uDD34", color: "#E53E3E" },
        { key: "due_today", label: "Today",     icon: "\uD83D\uDFE1", color: "#D69E2E" },
        { key: "this_week", label: "This Week", icon: "\uD83D\uDD35", color: "#3182CE" },
        { key: "stale",     label: "Stale",     icon: "\uD83D\uDFE0", color: "#DD6B20" },
        { key: "no_date",   label: "No Date",   icon: "\u26AA",       color: "#A0AEC0" },
        { key: "completed", label: "Done",     icon: "\uD83D\uDFE2", color: "#38A169" }
    ];

    var DAY_NAMES = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];

    /* ------------------------------------------------------------------ */
    /*  STATE                                                              */
    /* ------------------------------------------------------------------ */
    var allTasks        = [];
    var employees       = [];
    var projectNameMap  = {};
    var todayHoursMap   = {};
    var weekHoursMap    = {};
    var recentComments  = {};
    var recentTimeLogs  = {};
    var buckets         = { overdue: [], due_today: [], this_week: [], stale: [], no_date: [] };
    var lastActivity    = {};
    var filters         = { bucket: "overdue", person: "" };
    var lastUpdated     = null;
    var weeklyGridOpen  = false;
    var capacityOpen    = false;
    var EFFORT_HOURS    = { "S": 2, "M": 5, "L": 12, "XL": 30 };
    var WEEKLY_CAPACITY = 40;

    /* ------------------------------------------------------------------ */
    /*  UTILITY FUNCTIONS                                                   */
    /* ------------------------------------------------------------------ */
    function todayStart() { var d = new Date(); d.setHours(0, 0, 0, 0); return d; }

    function daysDiff(dateStr) {
        if (!dateStr) return null;
        var t = new Date(dateStr);
        t.setHours(0, 0, 0, 0);
        return Math.round((t - todayStart()) / 86400000);
    }

    function fmtDate(d) {
        if (!d) return "\u2014";
        var m = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
        var dt = new Date(d);
        return dt.getDate() + " " + m[dt.getMonth()] + " " + dt.getFullYear();
    }

    function esc(s) { if (!s) return ""; return $("<span>").text(s).html(); }

    function timeAgo(dateStr) {
        if (!dateStr) return "\u2014";
        var sec = Math.floor((Date.now() - new Date(dateStr).getTime()) / 1000);
        if (sec < 60) return "just now";
        var min = Math.floor(sec / 60);
        if (min < 60) return min + "m ago";
        var hr = Math.floor(min / 60);
        if (hr < 24) return hr + "h ago";
        var days = Math.floor(hr / 24);
        if (days === 1) return "yesterday";
        if (days < 7) return days + "d ago";
        return fmtDate(dateStr);
    }

    function activityColor(dateStr) {
        if (!dateStr) return COLORS.textSecondary;
        var hr = (Date.now() - new Date(dateStr).getTime()) / 3600000;
        if (hr < 24) return "#38A169";
        if (hr < 72) return "#D69E2E";
        return "#E53E3E";
    }

    function toDateStr(d) {
        return d.getFullYear() + "-" +
            String(d.getMonth() + 1).padStart(2, "0") + "-" +
            String(d.getDate()).padStart(2, "0");
    }

    function parseAssign(raw) {
        if (!raw) return [];
        try { var arr = JSON.parse(raw); return Array.isArray(arr) ? arr : []; }
        catch (e) { return []; }
    }

    function firstName(email) {
        if (!email) return "\u2014";
        for (var i = 0; i < employees.length; i++) {
            if (employees[i].user_id === email) {
                return employees[i].employee_name.split(" ")[0];
            }
        }
        return email.split("@")[0];
    }

    function fullName(email) {
        if (!email) return "";
        for (var i = 0; i < employees.length; i++) {
            if (employees[i].user_id === email) return employees[i].employee_name;
        }
        return email.split("@")[0];
    }

    function getWeekStart() {
        var d = new Date();
        d.setHours(0, 0, 0, 0);
        var day = d.getDay();
        var diff = day === 0 ? 6 : day - 1;
        d.setDate(d.getDate() - diff);
        return d;
    }

    function getDayIndex(dateStr) {
        var d = new Date(dateStr);
        var day = d.getDay();
        return day === 0 ? 6 : day - 1;
    }

    function roundHrs(n) { return Math.round(n * 10) / 10; }

    /* ------------------------------------------------------------------ */
    /*  INJECT STYLES                                                      */
    /* ------------------------------------------------------------------ */
    function injectStyles() {
