            "#team-pulse-dashboard { font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,'Helvetica Neue',Arial,sans-serif; color:" + COLORS.textPrimary + "; max-width:960px; margin:0 auto; padding:0 8px; }",

