            ".tp-refresh:hover { background:" + COLORS.bg + "; }",

            /* Risk bar */
            ".tp-risk-bar { display:flex; gap:6px; flex-wrap:wrap; margin-bottom:10px; }",
            ".tp-risk-pill { display:flex; align-items:center; gap:4px; padding:5px 12px; border-radius:20px; font-size:12px; font-weight:600; cursor:pointer; border:2px solid transparent; transition:all .15s; color:#fff; user-select:none; }",
            ".tp-risk-pill:hover { opacity:.9; }",
            ".tp-risk-pill.active { border-color:" + COLORS.textPrimary + "; box-shadow:0 0 0 1px " + COLORS.textPrimary + "; }",
            ".tp-risk-count { background:rgba(255,255,255,.3); border-radius:10px; padding:0 6px; font-size:11px; }",

            /* Team strip */
