    /* ------------------------------------------------------------------ */
    /*  DATA LOADING                                                       */
    /* ------------------------------------------------------------------ */
    function loadAllData() {
        var $root = $("#team-pulse-dashboard");
        $root.html('<div class="tp-loading">Loading team data...</div>');

        var today = todayStart();
        var todayStr = toDateStr(today);
        var threeDaysAgo = new Date(today);
        threeDaysAgo.setDate(threeDaysAgo.getDate() - 3);
        var threeDaysAgoStr = toDateStr(threeDaysAgo);
        var thirtyDaysAgo = new Date(today);
        thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
        var thirtyDaysAgoStr = toDateStr(thirtyDaysAgo);
        var weekStart = getWeekStart();
        var weekStartStr = toDateStr(weekStart);

        Promise.all([
            /* 0 - Tasks */
            frappe.xcall("frappe.client.get_list", {
                doctype: "Task",
                filters: { status: ["not in", ["Template", "Cancelled"]] },
                fields: ["name","subject","status","priority","exp_start_date","exp_end_date",
                          "_assign","progress","project","owner","modified","custom_estimated_effort"],
                order_by: "modified desc",
                limit_page_length: 0
            }),
            /* 1 - Employees */
            frappe.xcall("frappe.client.get_list", {
                doctype: "Employee",
                filters: { status: "Active" },
                fields: ["name","employee_name","user_id","designation"],
                limit_page_length: 0
            }),
            /* 2 - Projects */
            frappe.xcall("frappe.client.get_list", {
                doctype: "Project",
                fields: ["name","project_name"],
                limit_page_length: 0
            }),
            /* 3 - Recent comments (last 30 days for activity tracking) */
            frappe.xcall("frappe.client.get_list", {
                doctype: "Comment",
                filters: {
                    reference_doctype: "Task",
                    comment_type: "Comment",
                    creation: [">=", thirtyDaysAgoStr]
                },
                fields: ["reference_name","creation"],
                limit_page_length: 0
            }),
            /* 4 - Today's timesheets */
            frappe.xcall("frappe.client.get_list", {
                doctype: "Timesheet",
                filters: { start_date: todayStr, docstatus: ["in", [0, 1]] },
                fields: ["name","employee","employee_name"],
                limit_page_length: 0
            }),
            /* 5 - Timesheets last 30 days (for activity tracking + weekly grid) */
            frappe.xcall("frappe.client.get_list", {
                doctype: "Timesheet",
                filters: { start_date: [">=", thirtyDaysAgoStr], docstatus: ["in", [0, 1]] },
                fields: ["name","employee","employee_name"],
                limit_page_length: 0
            })
        ]).then(function (results) {
            allTasks = results[0] || [];
            employees = results[1] || [];
            var projects = results[2] || [];
            var comments = results[3] || [];
            var todayTimesheets = results[4] || [];
            var weekTimesheets = results[5] || [];

            /* Build project name map */
            projectNameMap = {};
            for (var i = 0; i < projects.length; i++) {
                projectNameMap[projects[i].name] = projects[i].project_name;
            }

            /* Build recent comments map (task -> latest creation) */
            recentComments = {};
            for (var i = 0; i < comments.length; i++) {
                var c = comments[i];
                if (!recentComments[c.reference_name] || c.creation > recentComments[c.reference_name]) {
                    recentComments[c.reference_name] = c.creation;
                }
            }

            /* Fetch today's timesheet details for hours */
            var todayDetailPromises = todayTimesheets.map(function (ts) {
                return frappe.xcall("frappe.client.get", { doctype: "Timesheet", name: ts.name });
            });

            var weekDetailPromises = weekTimesheets.map(function (ts) {
                return frappe.xcall("frappe.client.get", { doctype: "Timesheet", name: ts.name });
            });

            return Promise.all([
                Promise.all(todayDetailPromises),
                Promise.all(weekDetailPromises)
            ]).then(function (detailResults) {
                var todayDetails = detailResults[0] || [];
                var weekDetails = detailResults[1] || [];

                /* Build todayHoursMap */
                todayHoursMap = {};
                for (var i = 0; i < todayDetails.length; i++) {
                    var ts = todayDetails[i];
                    var empName = ts.employee_name || "";
                    var logs = ts.time_logs || [];
                    for (var j = 0; j < logs.length; j++) {
                        var hrs = logs[j].hours || 0;
                        todayHoursMap[empName] = (todayHoursMap[empName] || 0) + hrs;

                        /* Also mark tasks with recent time logs */
                        if (logs[j].task) {
                            var ft = logs[j].from_time || logs[j].to_time || "";
                            if (!recentTimeLogs[logs[j].task] || ft > recentTimeLogs[logs[j].task]) {
                                recentTimeLogs[logs[j].task] = ft;
                            }
                        }
                    }
                }

                /* Build weekHoursMap */
                weekHoursMap = {};
                for (var i = 0; i < weekDetails.length; i++) {
                    var ts = weekDetails[i];
                    var empName = ts.employee_name || "";
                    if (!weekHoursMap[empName]) {
                        weekHoursMap[empName] = {};
                        for (var d = 0; d < DAY_NAMES.length; d++) {
                            weekHoursMap[empName][DAY_NAMES[d]] = 0;
                        }
                    }
                    var logs = ts.time_logs || [];
                    for (var j = 0; j < logs.length; j++) {
                        var hrs = logs[j].hours || 0;
                        var logDate = logs[j].from_time || logs[j].start_date || "";
                        if (logDate) {
                            var dayIdx = getDayIndex(logDate);
                            if (dayIdx >= 0 && dayIdx < DAY_NAMES.length) {
                                weekHoursMap[empName][DAY_NAMES[dayIdx]] += hrs;
                            }
                        }
                        /* Mark tasks with recent time logs from this week */
                        if (logs[j].task) {
                            var ft = logs[j].from_time || logs[j].to_time || "";
                            if (!recentTimeLogs[logs[j].task] || ft > recentTimeLogs[logs[j].task]) {
                                recentTimeLogs[logs[j].task] = ft;
                            }
                        }
                    }
                }

                processTasks();
                lastUpdated = new Date();
                render();
            });
        }).catch(function (err) {
            console.error("Team Pulse load error:", err);
            $root.html('<div class="tp-empty">Failed to load data. Check console for details.</div>');
        });
    }

    /* ------------------------------------------------------------------ */
    /*  PROCESSING                                                         */
    /* ------------------------------------------------------------------ */
    function processTasks() {
        var today = todayStart();
        var todayStr = toDateStr(today);
        var tomorrow = new Date(today);
        tomorrow.setDate(tomorrow.getDate() + 1);
        var endOfWeek = new Date(today);
        var dayOfWeek = today.getDay();
        var daysToSunday = dayOfWeek === 0 ? 0 : 7 - dayOfWeek;
        endOfWeek.setDate(endOfWeek.getDate() + daysToSunday);
        var endOfWeekStr = toDateStr(endOfWeek);
        var tomorrowStr = toDateStr(tomorrow);

        var threeDaysAgo = new Date(today);
        threeDaysAgo.setDate(threeDaysAgo.getDate() - 3);

        buckets = { overdue: [], due_today: [], this_week: [], stale: [], no_date: [], completed: [] };
        lastActivity = {};

        for (var i = 0; i < allTasks.length; i++) {
            var t = allTasks[i];
            var endDate = t.exp_end_date ? t.exp_end_date.split(" ")[0] : "";
            var st = t.status;
            var isDone = (st === "Completed" || st === "Cancelled");

            /* Compute last REAL activity = max(latest comment, latest timelog)
               Only fall back to task.modified if no comments or timelogs exist at all */
            var commentTime = recentComments[t.name] || "";
            var timelogTime = recentTimeLogs[t.name] || "";
            var best = "";
            if (commentTime > best) best = commentTime;
            if (timelogTime > best) best = timelogTime;
            if (!best) best = t.modified || ""; // fallback only if zero real signals
            lastActivity[t.name] = best;

            if (isDone) { buckets.completed.push(t); continue; }

            /* Bucket classification */
            if (endDate && endDate < todayStr) {
                buckets.overdue.push(t);
            } else if (endDate === todayStr) {
                buckets.due_today.push(t);
            } else if (endDate && endDate >= tomorrowStr && endDate <= endOfWeekStr) {
                buckets.this_week.push(t);
            }

            /* Stale check: last real activity (across all 3 signals) is older than 3 days */
            if ((st === "Open" || st === "Working") && best) {
                var bestDate = new Date(best);
                if (bestDate < threeDaysAgo) {
                    buckets.stale.push(t);
                }
            }

            /* No date */
            if (!endDate) {
                buckets.no_date.push(t);
            }
        }
    }

    /* ------------------------------------------------------------------ */
    /*  RENDERING                                                          */
    /* ------------------------------------------------------------------ */
    function render() {
        var $root = $("#team-pulse-dashboard");
        $root.empty();

        $root.append(renderHeader());
        $root.append(renderRiskBar());
        $root.append(renderTeamStrip());
        $root.append(renderTaskList());
        $root.append(renderCapacitySection());
        $root.append(renderWeeklySection());

        bindEvents();
    }

    function renderHeader() {
        var timeStr = lastUpdated ? timeAgo(lastUpdated.toISOString()) : "\u2014";
        return [
            '<div class="tp-header">',
            '  <div>',
            '    <p class="tp-title">Team Pulse</p>',
            '    <p class="tp-meta">Last updated: ' + esc(timeStr) + '</p>',
            '  </div>',
            '  <button class="tp-refresh" id="tp-refresh-btn">\u21BB Refresh</button>',
            '</div>'
        ].join("\n");
    }

    function renderRiskBar() {
        var html = '<div class="tp-risk-bar">';
        for (var i = 0; i < BUCKET_META.length; i++) {
            var b = BUCKET_META[i];
            var count = buckets[b.key] ? buckets[b.key].length : 0;
            var active = filters.bucket === b.key ? " active" : "";
            html += '<div class="tp-risk-pill' + active + '" data-bucket="' + b.key + '" style="background:' + b.color + '">';
            html += b.icon + ' ' + esc(b.label);
            html += ' <span class="tp-risk-count">' + count + '</span>';
            html += '</div>';
        }
        html += '</div>';
        return html;
    }

    function renderTeamStrip() {
        if (!employees.length) return "";
        /* Sort: those with hours first, then alphabetical */
        var sorted = employees.slice().sort(function (a, b) {
            var ha = todayHoursMap[a.employee_name] || 0;
            var hb = todayHoursMap[b.employee_name] || 0;
            if (hb !== ha) return hb - ha;
            return (a.employee_name || "").localeCompare(b.employee_name || "");
        });

        var html = '<div class="tp-team-strip">';
        /* "All" chip */
        var allActive = !filters.person ? " active" : "";
        html += '<div class="tp-team-chip' + allActive + '" data-person="">All</div>';

        for (var i = 0; i < sorted.length; i++) {
            var emp = sorted[i];
            var hrs = roundHrs(todayHoursMap[emp.employee_name] || 0);
            var isActive = filters.person === emp.user_id ? " active" : "";
            var isZero = hrs === 0 ? " zero-hrs" : "";
            html += '<div class="tp-team-chip' + isActive + isZero + '" data-person="' + esc(emp.user_id || "") + '">';
            html += esc(emp.employee_name.split(" ")[0]);
            html += '<span class="tp-chip-hrs">' + hrs + 'h</span>';
            html += '</div>';
        }
        html += '</div>';
        return html;
    }

    function getFilteredTasks() {
        var list = buckets[filters.bucket] || [];
        if (!filters.person) return list;
        return list.filter(function (t) {
            var assigned = parseAssign(t._assign);
            return assigned.indexOf(filters.person) !== -1;
        });
    }

    function renderTaskList() {
        var tasks = getFilteredTasks();
        var activeBucket = BUCKET_META.filter(function (b) { return b.key === filters.bucket; })[0];
        var label = activeBucket ? activeBucket.label : "Tasks";
        var personLabel = filters.person ? " \u2014 " + firstName(filters.person) : "";

        var html = '<div class="tp-section-label">' + esc(label) + personLabel + ' (' + tasks.length + ')</div>';
        html += '<div class="tp-task-list">';

        if (!tasks.length) {
            html += '<div class="tp-empty">No tasks in this bucket' + (filters.person ? " for this person" : "") + '.</div>';
            html += '</div>';
            return html;
        }

        /* Desktop header */
        html += '<div class="tp-task-row tp-task-head">';
        html += '<div></div>';
        html += '<div>Task</div>';
        html += '<div>Assignee</div>';
        html += '<div>Project</div>';
        html += '<div>Status</div>';
        html += '<div>Due</div>';
        html += '<div>Activity</div>';
        html += '</div>';

        for (var i = 0; i < tasks.length; i++) {
            var t = tasks[i];
            var isStale = buckets.stale.some(function (s) { return s.name === t.name; });
            var assigned = parseAssign(t._assign);
            var assigneeDisplay = assigned.length ? firstName(assigned[0]) : "\u2014";
            if (assigned.length > 1) assigneeDisplay += " +" + (assigned.length - 1);
            var projName = t.project ? (projectNameMap[t.project] || t.project) : "\u2014";
            var endDate = t.exp_end_date ? t.exp_end_date.split(" ")[0] : "";
            var act = lastActivity[t.name] || t.modified || "";
            var statusColor = COLORS.status[t.status] || COLORS.textSecondary;

            html += '<div class="tp-task-row">';

            /* Stale dot */
            html += '<div>';
            if (isStale) {
                html += '<span class="tp-stale-dot" style="background:#E53E3E;" title="Stale: no activity in 3+ days"></span>';
            }
            html += '</div>';

            /* Task subject + mobile meta */
            html += '<div class="tp-task-subject">';
            html += '<a href="/app/task/' + esc(t.name) + '" title="' + esc(t.subject) + '">' + esc(t.subject) + '</a>';
            /* Mobile meta line */
            html += '<div class="tp-card-meta">';
            html += '<span>' + esc(assigneeDisplay) + '</span>';
            html += '<span class="tp-status-badge" style="background:' + statusColor + '">' + esc(t.status) + '</span>';
            html += '<span>' + fmtDate(endDate) + '</span>';
            html += '<span style="color:' + activityColor(act) + '">' + timeAgo(act) + '</span>';
            html += '</div>';
            html += '</div>';

            /* Desktop columns (hidden on mobile via .tp-desk-col) */
            html += '<div class="tp-desk-col">' + esc(assigneeDisplay) + '</div>';
            html += '<div class="tp-desk-col" style="font-size:11px;color:' + COLORS.textSecondary + ';white-space:nowrap;overflow:hidden;text-overflow:ellipsis;" title="' + esc(projName) + '">' + esc(projName) + '</div>';
            html += '<div class="tp-desk-col"><span class="tp-status-badge" style="background:' + statusColor + '">' + esc(t.status) + '</span></div>';
            html += '<div class="tp-desk-col" style="font-size:11px;">' + fmtDate(endDate) + '</div>';
            html += '<div class="tp-desk-col" style="font-size:11px;color:' + activityColor(act) + '">' + timeAgo(act) + '</div>';

            html += '</div>';
        }

        html += '</div>';
        return html;
    }

    /* ---------- Capacity View ---------- */
    function renderCapacitySection() {
        var arrow = capacityOpen ? "\u25BE" : "\u25B8";
        var html = '<button class="tp-weekly-toggle" id="tp-capacity-toggle">' + arrow + ' Team Capacity</button>';

        if (!capacityOpen) return html;

        // Build capacity data per person from active (non-completed/cancelled) tasks
        var personLoad = {}; // { employeeName: { total: hours, tasks: [{subject, effort, hours, project}] } }

        for (var i = 0; i < allTasks.length; i++) {
            var t = allTasks[i];
            if (t.status === "Completed" || t.status === "Cancelled") continue;
            var assigned = parseAssign(t._assign);
            var effort = t.custom_estimated_effort || "M";
            var hrs = EFFORT_HOURS[effort] || 5;
            var projName = t.project ? (projectNameMap[t.project] || t.project) : "";

            for (var j = 0; j < assigned.length; j++) {
                var empName = fullName(assigned[j]);
                if (!personLoad[empName]) personLoad[empName] = { total: 0, tasks: [] };
                personLoad[empName].total += hrs;
                personLoad[empName].tasks.push({
                    subject: t.subject || t.name,
                    effort: effort,
                    hours: hrs,
                    project: projName,
                    status: t.status,
                    due: t.exp_end_date ? t.exp_end_date.split(" ")[0] : ""
                });
            }
        }

        // Sort by total hours descending
        var people = Object.keys(personLoad).sort(function(a, b) {
            return personLoad[b].total - personLoad[a].total;
        });

        html += '<div class="tp-capacity-grid">';

        for (var p = 0; p < people.length; p++) {
            var name = people[p];
            var data = personLoad[name];
            var pct = Math.min(100, Math.round(data.total / WEEKLY_CAPACITY * 100));
            var barColor = pct > 100 ? "#E53E3E" : pct > 80 ? "#D69E2E" : "#3182CE";
            var label = pct > 100 ? "OVERLOADED" : pct > 80 ? "Near capacity" : pct < 30 ? "Has bandwidth" : "";

            html += '<div class="tp-cap-row">';
            html += '<div class="tp-cap-name">' + esc(name) + '</div>';
            html += '<div class="tp-cap-bar-wrap">';
            html += '<div class="tp-cap-bar" style="width:' + Math.min(pct, 100) + '%;background:' + barColor + ';"></div>';
            html += '</div>';
            html += '<div class="tp-cap-hrs" style="color:' + barColor + ';">' + data.total + 'h';
            if (label) html += ' <span style="font-size:9px;font-weight:400;color:' + barColor + ';">' + label + '</span>';
            html += '</div>';
            html += '</div>';

            // Task list under this person
            html += '<div class="tp-cap-tasks">';
            data.tasks.sort(function(a, b) { return b.hours - a.hours; });
            for (var ti = 0; ti < data.tasks.length; ti++) {
                var task = data.tasks[ti];
                var effortBg = task.effort === "XL" ? "#FFF5F5" : task.effort === "L" ? "#FFFFF0" : task.effort === "M" ? "#EBF8FF" : "#F0FFF4";
                var effortCol = task.effort === "XL" ? "#E53E3E" : task.effort === "L" ? "#D69E2E" : task.effort === "M" ? "#3182CE" : "#38A169";
                html += '<div class="tp-cap-task">';
                html += '<span class="tp-cap-effort" style="background:' + effortBg + ';color:' + effortCol + ';">' + task.effort + '</span> ';
                html += '<span class="tp-cap-task-name">' + esc(task.subject) + '</span>';
                if (task.project) html += ' <span style="color:' + COLORS.textSecondary + ';font-size:10px;">(' + esc(task.project) + ')</span>';
                html += '</div>';
            }
            html += '</div>';
        }

        // People with no tasks
        var assignedPeople = {};
        people.forEach(function(p) { assignedPeople[p] = true; });
        var idle = [];
        employees.forEach(function(emp) {
            if (!assignedPeople[emp.employee_name]) idle.push(emp.employee_name);
        });
        if (idle.length > 0) {
            html += '<div style="margin-top:10px;padding:8px 12px;background:#F0FFF4;border-radius:6px;font-size:12px;color:#38A169;">';
            html += '<strong>No tasks assigned:</strong> ' + idle.join(", ");
            html += '</div>';
        }

        html += '</div>';
        return html;
    }

    function renderWeeklySection() {
        var arrow = weeklyGridOpen ? "\u25BE" : "\u25B8";
        var html = '<button class="tp-weekly-toggle" id="tp-weekly-toggle">' + arrow + ' Weekly Hours</button>';

        if (!weeklyGridOpen) return html;

        html += '<div class="tp-weekly-grid"><table>';

        /* Header */
        html += '<tr><th>Team Member</th>';
        for (var d = 0; d < DAY_NAMES.length; d++) {
            html += '<th>' + DAY_NAMES[d] + '</th>';
        }
        html += '<th>Total</th></tr>';

        /* Sort employees alphabetically */
        var sorted = employees.slice().sort(function (a, b) {
            return (a.employee_name || "").localeCompare(b.employee_name || "");
        });

        var colTotals = {};
        for (var d = 0; d < DAY_NAMES.length; d++) colTotals[DAY_NAMES[d]] = 0;
        var grandTotal = 0;

        for (var i = 0; i < sorted.length; i++) {
            var emp = sorted[i];
            var empName = emp.employee_name;
            var weekData = weekHoursMap[empName] || {};
            var rowTotal = 0;

            html += '<tr><td>' + esc(empName) + '</td>';
            for (var d = 0; d < DAY_NAMES.length; d++) {
                var hrs = roundHrs(weekData[DAY_NAMES[d]] || 0);
                rowTotal += hrs;
                colTotals[DAY_NAMES[d]] += hrs;
                html += '<td><span class="tp-grid-cell" style="background:' + cellColor(hrs) + '">' + (hrs || "\u2014") + '</span></td>';
            }
            rowTotal = roundHrs(rowTotal);
            grandTotal += rowTotal;
            html += '<td><strong>' + rowTotal + '</strong></td>';
            html += '</tr>';
        }

        /* Column totals */
        html += '<tr class="tp-total-row"><td>Total</td>';
        for (var d = 0; d < DAY_NAMES.length; d++) {
            html += '<td><strong>' + roundHrs(colTotals[DAY_NAMES[d]]) + '</strong></td>';
        }
        html += '<td><strong>' + roundHrs(grandTotal) + '</strong></td>';
        html += '</tr>';

        html += '</table></div>';
        return html;
    }

    function cellColor(hrs) {
        if (!hrs || hrs === 0) return "transparent";
        if (hrs < 1) return "rgba(49,130,206,0.08)";
        if (hrs <= 3) return "rgba(49,130,206,0.18)";
        if (hrs <= 6) return "rgba(49,130,206,0.35)";
        return "rgba(49,130,206,0.55)";
    }

    /* ------------------------------------------------------------------ */
    /*  EVENT BINDING                                                      */
    /* ------------------------------------------------------------------ */
    function bindEvents() {
        /* Risk pill click */
        $(".tp-risk-pill").off("click").on("click", function () {
            filters.bucket = $(this).data("bucket");
            render();
        });

        /* Team chip click */
        $(".tp-team-chip").off("click").on("click", function () {
            var person = $(this).data("person") || "";
            filters.person = (filters.person === person) ? "" : person;
            render();
        });

        /* Refresh */
        $("#tp-refresh-btn").off("click").on("click", function () {
            loadAllData();
        });

        /* Weekly toggle */
        $("#tp-capacity-toggle").off("click").on("click", function () {
            capacityOpen = !capacityOpen;
            render();
        });

        $("#tp-weekly-toggle").off("click").on("click", function () {
            weeklyGridOpen = !weeklyGridOpen;
            render();
        });
    }

    /* ------------------------------------------------------------------ */
    /*  INIT                                                               */
    /* ------------------------------------------------------------------ */
    var ALLOWED_USERS = [
        "raghav.bansal@sevenlabs.in",
        "Administrator"
    ];

    frappe.ready(function () {
        setTimeout(function () {
            var $root = $("#team-pulse-dashboard");
            if (!$root.length) return;

            if (ALLOWED_USERS.indexOf(frappe.session.user) === -1) {
                $root.html('<div style="text-align:center;padding:60px 20px;color:#718096;"><div style="font-size:48px;margin-bottom:12px;">&#128274;</div><div style="font-size:16px;font-weight:600;">Access Restricted</div><div style="margin-top:8px;">This dashboard is only available to authorized managers.</div><div style="margin-top:16px;"><a href="/my-tasks" style="color:#3182CE;">Go to My Tasks &rarr;</a></div></div>');
                return;
            }

            injectStyles();
            loadAllData();
        }, 300);
    });

})();
